-- ================================================================
-- 완료
-- CREDIT_CARD_APPLICATIONS: 3건 (user 51/52/54)
-- CHECK_CARD_APPLICATIONS:  3건 (user 51/52/54)
-- USER_CARDS:               6장 (신용 3 + 체크 3)
-- CARD_TRANSACTIONS:       150건 (1인 50건, 신용 25 + 체크 25)
-- 날짜 범위: 2022-12 ~ 2026-06
-- ================================================================

SELECT user_id, card_type, COUNT(*) AS cnt
FROM CARD_TRANSACTIONS
WHERE user_id IN (51, 52, 54)
GROUP BY user_id, card_type
ORDER BY user_id, card_type;

-- 신청 건수 확인
SELECT user_id, COUNT(*) FROM CREDIT_CARD_APPLICATIONS 
WHERE user_id IN (51,52,54) GROUP BY user_id;

SELECT user_id, COUNT(*) FROM CHECK_CARD_APPLICATIONS 
WHERE user_id IN (51,52,54) GROUP BY user_id;

-- 유저카드 건수 확인
SELECT user_id, COUNT(*) FROM USER_CARDS
WHERE user_id IN (51,52,54) GROUP BY user_id;